<template>
    <div class="sidebar">
        <el-menu
            class="sidebar-el-menu"
            :default-active="onRoutes"
            :collapse="collapse"
            background-color="#324157"
            text-color="#bfcbd9"
            active-text-color="#20a0ff"
            unique-opened
            router
        >
            <template v-for="item in items">
                <template v-if="item.subs">
                    <el-submenu :index="item.index" :key="item.index">
                        <template slot="title">
                            <i :class="item.icon"></i>
                            <span slot="title">{{ item.title }}</span>
                        </template>
                        <template v-for="subItem in item.subs">
                            <el-submenu
                                v-if="subItem.subs"
                                :index="subItem.index"
                                :key="subItem.index"
                            >
                                <template slot="title">{{ subItem.title }}</template>
                                <el-menu-item
                                    v-for="(threeItem,i) in subItem.subs"
                                    :key="i"
                                    :index="threeItem.index"
                                >{{ threeItem.title }}</el-menu-item>
                            </el-submenu>
                            <el-menu-item
                                v-else
                                :index="subItem.index"
                                :key="subItem.index"
                            >{{ subItem.title }}</el-menu-item>
                        </template>
                    </el-submenu>
                </template>
                <template v-else>
                    <el-menu-item :index="item.index" :key="item.index">
                        <i :class="item.icon"></i>
                        <span slot="title">{{ item.title }}</span>
                    </el-menu-item>
                </template>
            </template>
        </el-menu>
    </div>
</template>

<script>
import bus from '../common/bus';

export default {
    data() {
        return {
            collapse: false,
            items: [
                {   
                    icon: 'el-icon-s-release',
                    index: '1',
                    title: '发布系统',
                    subs:[
                        {
                            index: 'releaseCode',
                            title: '发布项目'
                        },
                        {
                            index: 'deploymentLogs',
                            title: '发布日志'
                        },
                    ]
                }
            ]
        };
    },
    computed: {
        onRoutes() {
            return this.$route.path.replace('/', '');
        }
    },
    created() {
        let role = localStorage.getItem('role');
        if(role=='1'){
            this.items.push(
                {   
                    icon: 'el-icon-s-order',
                    index: '2',
                    title: '资源管理',
                    subs:[
                        {
                            index: 'engineroom',
                            title: '机房管理'
                        },
                        {
                            index: 'service',
                            title: '服务器'
                        },
                    ]
                },
                {   
                    icon: 'el-icon-s-custom',
                    index: '3',
                    title: '后台管理',
                    subs:[
                        {
                            index: 'department',
                            title: '部门管理'
                        },
                        {
                            index: 'user',
                            title: '用户管理'
                        },
                    ]
                },
            )
            this.items[0].subs.push(
                {
                    index: 'projectConfig',
                    title: '项目配置'
                }
            )
        }
        // 通过 Event Bus 进行组件间通信，来折叠侧边栏
        bus.$on('collapse', msg => {
            this.collapse = msg;
            bus.$emit('collapse-content', msg);
        });
    }
};
</script>

<style scoped>
.sidebar {
    display: block;
    position: absolute;
    left: 0;
    top: 60px;
    bottom: 0;
    overflow-y: scroll;
}
.sidebar::-webkit-scrollbar {
    width: 0;
}
.sidebar-el-menu:not(.el-menu--collapse) {
    width: 200px;
}
.sidebar > ul {
    height: 100%;
}
</style>



